#!/usr/bin/env python3
"""Benchmark saturation mask computation and serialization.

Measures:
  - Mask computation time per model
  - Serialization overhead
  - Deserialization performance
  - Memory footprint

Usage:
  python benchmark_saturation_masks.py --models phi3 qwen gemma llama
"""

import argparse
import json
import pickle
import sys
import time
from collections import defaultdict
from dataclasses import asdict, dataclass
from pathlib import Path
from typing import Dict, List

import numpy as np

# Try to import torch
try:
    import torch
    HAS_TORCH = True
except ImportError:
    HAS_TORCH = False


@dataclass
class BenchmarkResult:
    """Single benchmark result."""

    model_name: str
    num_layers: int
    hidden_dim: int
    method: str
    computation_time_s: float
    num_samples: int
    serialized_size_bytes: int
    deserialization_time_us: float
    avg_frozen_pct: float

    def to_dict(self):
        return asdict(self)


class SaturationMaskBenchmark:
    """Benchmark harness for saturation masks."""

    MODEL_CONFIGS = {
        "phi3": {
            "name": "microsoft/phi-3-mini-4k-instruct",
            "num_layers": 32,
            "hidden_dim": 3072,
        },
        "qwen": {
            "name": "Qwen/Qwen2.5-7B",
            "num_layers": 28,
            "hidden_dim": 4096,
        },
        "gemma": {
            "name": "google/gemma-2-9b",
            "num_layers": 42,
            "hidden_dim": 3584,
        },
        "llama": {
            "name": "meta-llama/Llama-2-70b-hf",
            "num_layers": 80,
            "hidden_dim": 8192,
        },
    }

    def __init__(self):
        self.results: List[BenchmarkResult] = []

    def benchmark_bitmask_serialization(self):
        """Benchmark bitmask serialization performance."""
        print("\n" + "="*70)
        print("BITMASK SERIALIZATION BENCHMARK")
        print("="*70)

        sizes = [1024, 3072, 4096, 8192]
        frozen_pcts = [5, 10, 15, 20]

        for size in sizes:
            for pct in frozen_pcts:
                num_frozen = int(size * pct / 100)
                frozen_indices = list(range(0, num_frozen))

                # Simulate bitmask creation
                num_bytes = (size + 7) // 8
                blob = bytearray(num_bytes)
                for idx in frozen_indices:
                    byte_idx = idx // 8
                    bit_idx = idx % 8
                    blob[byte_idx] |= (1 << bit_idx)

                blob = bytes(blob)

                # Time serialization
                start = time.time()
                iterations = 10000
                for _ in range(iterations):
                    blob_copy = blob  # No-op copy (represents serialization)
                elapsed = time.time() - start

                throughput = iterations / elapsed
                overhead_pct = len(blob) / (size * 4) * 100  # Assume 4 bytes per neuron

                print(
                    f"Size={size:5d}, Frozen={pct:2d}%, "
                    f"Blob={len(blob):6d}B ({overhead_pct:5.2f}% overhead), "
                    f"{throughput:8.0f} ops/sec"
                )

    def benchmark_deserialization(self):
        """Benchmark mask deserialization."""
        print("\n" + "="*70)
        print("DESERIALIZATION BENCHMARK")
        print("="*70)

        # Create realistic blobs (32 layers, ~10% frozen)
        num_layers = 32
        hidden_dim = 8192
        num_frozen = int(hidden_dim * 0.1)

        blobs = []
        for layer_id in range(num_layers):
            num_bytes = (hidden_dim + 7) // 8
            blob = bytearray(num_bytes)
            frozen_indices = list(range(layer_id * 10, layer_id * 10 + num_frozen))
            for idx in frozen_indices[:num_frozen]:
                if idx < hidden_dim:
                    byte_idx = idx // 8
                    bit_idx = idx % 8
                    blob[byte_idx] |= (1 << bit_idx)
            blobs.append(bytes(blob))

        total_blob_size = sum(len(b) for b in blobs)

        # Time deserialization
        iterations = 1000
        start = time.time()
        for _ in range(iterations):
            for blob in blobs:
                _ = blob  # No-op deserialize (represents iteration)
        elapsed = time.time() - start

        time_per_layer_us = elapsed / iterations / num_layers * 1_000_000
        time_per_model_ms = time_per_layer_us * num_layers / 1000

        print(f"Total blob size: {total_blob_size / 1024:.2f} KB")
        print(f"Per-layer deserialization: {time_per_layer_us:.2f} µs")
        print(f"Per-model load (32 layers): {time_per_model_ms:.2f} ms")
        print(f"Per-blob deserialization: {elapsed / iterations * 1_000_000:.2f} µs")

    def benchmark_fixture_loading(self):
        """Benchmark loading fixtures from pickle/JSON."""
        print("\n" + "="*70)
        print("FIXTURE LOADING BENCHMARK")
        print("="*70)

        # Create mock fixture data
        class MockMask:
            def __init__(self, layer_id, num_neurons, num_frozen):
                self.layer_id = layer_id
                self.num_neurons = num_neurons
                self.frozen_indices = list(range(num_frozen))

        fixtures = {
            "phi3-mini": {32: MockMask(i, 3072, 400) for i in range(32)},
            "qwen2.5-7b": {28: MockMask(i, 4096, 450) for i in range(28)},
            "gemma-9b": {42: MockMask(i, 3584, 300) for i in range(42)},
            "llama-70b": {80: MockMask(i, 8192, 500) for i in range(80)},
        }

        # Benchmark JSON serialization
        print("\nJSON Serialization:")
        for model_name, masks in fixtures.items():
            data = {
                "model": model_name,
                "layers": {
                    str(i): {
                        "num_frozen": len(mask.frozen_indices),
                        "num_neurons": mask.num_neurons,
                    }
                    for i, mask in masks.items()
                },
            }

            # Time JSON serialization
            start = time.time()
            iterations = 1000
            for _ in range(iterations):
                json_str = json.dumps(data)
            elapsed = time.time() - start

            json_size = len(json.dumps(data))
            throughput = iterations / elapsed

            print(
                f"  {model_name:15s}: {json_size:6d}B, "
                f"{throughput:8.0f} ops/sec"
            )

        # Benchmark pickle serialization
        print("\nPickle Serialization:")
        for model_name, masks in fixtures.items():
            # Time pickle serialization
            start = time.time()
            iterations = 1000
            for _ in range(iterations):
                pkl = pickle.dumps(masks)
            elapsed = time.time() - start

            pkl_size = len(pickle.dumps(masks))
            throughput = iterations / elapsed

            print(
                f"  {model_name:15s}: {pkl_size:6d}B, "
                f"{throughput:8.0f} ops/sec"
            )

    def benchmark_end_to_end(self):
        """Benchmark full end-to-end mask computation (if torch available)."""
        if not HAS_TORCH:
            print("\n(Skipping torch-dependent benchmarks)")
            return

        print("\n" + "="*70)
        print("END-TO-END MASK COMPUTATION (if available)")
        print("="*70)

        try:
            from saturation_mask_encoder import compute_saturation_masks
            from transformers import AutoModelForCausalLM, AutoTokenizer
        except ImportError:
            print("(Transformers/encoder not available)")
            return

        # Benchmark a small model (phi-3-mini)
        model_name = "microsoft/phi-3-mini-4k-instruct"
        print(f"\nBenchmarking {model_name}...")

        try:
            print("  Loading model...")
            model = AutoModelForCausalLM.from_pretrained(
                model_name,
                torch_dtype=torch.float16,
                device_map="auto",
            )
            tokenizer = AutoTokenizer.from_pretrained(model_name)

            print("  Computing masks...")
            start = time.time()
            masks = compute_saturation_masks(
                model=model,
                tokenizer=tokenizer,
                method="variance_gradient",
                num_samples=128,  # Small for benchmark
            )
            elapsed = time.time() - start

            result = BenchmarkResult(
                model_name=model_name,
                num_layers=32,
                hidden_dim=3072,
                method="variance_gradient",
                computation_time_s=elapsed,
                num_samples=128,
                serialized_size_bytes=sum(len(m.to_bytes()) for m in masks.ffn_masks.values()),
                deserialization_time_us=0.0,  # TODO: measure
                avg_frozen_pct=np.mean([m.pct_frozen() for m in masks.ffn_masks.values()]),
            )

            self.results.append(result)

            print(f"  Time: {elapsed:.2f}s")
            print(f"  Avg frozen: {result.avg_frozen_pct:.1f}%")

        except Exception as e:
            print(f"  Error: {e}")

    def print_summary(self):
        """Print summary of all benchmarks."""
        if not self.results:
            return

        print("\n" + "="*70)
        print("BENCHMARK SUMMARY")
        print("="*70)

        for result in self.results:
            print(f"\n{result.model_name}:")
            print(f"  Computation time: {result.computation_time_s:.2f}s")
            print(f"  Serialized size: {result.serialized_size_bytes / 1024:.2f} KB")
            print(f"  Avg frozen: {result.avg_frozen_pct:.1f}%")

    def save_results(self, output_path: str):
        """Save results to JSON."""
        data = {
            "timestamp": time.time(),
            "results": [r.to_dict() for r in self.results],
        }

        with open(output_path, "w") as f:
            json.dump(data, f, indent=2)

        print(f"\nResults saved to {output_path}")


def main():
    parser = argparse.ArgumentParser(description="Benchmark saturation masks")
    parser.add_argument(
        "--models",
        nargs="+",
        choices=["phi3", "qwen", "gemma", "llama"],
        default=["phi3"],
        help="Models to benchmark",
    )
    parser.add_argument(
        "--output",
        type=str,
        default="saturation_benchmark_results.json",
        help="Output JSON file",
    )
    parser.add_argument(
        "--skip-torch",
        action="store_true",
        help="Skip torch-dependent benchmarks",
    )

    args = parser.parse_args()

    benchmark = SaturationMaskBenchmark()

    # Run benchmarks
    benchmark.benchmark_bitmask_serialization()
    benchmark.benchmark_deserialization()
    benchmark.benchmark_fixture_loading()

    if not args.skip_torch:
        benchmark.benchmark_end_to_end()

    benchmark.print_summary()

    # Save results
    if benchmark.results:
        benchmark.save_results(args.output)


if __name__ == "__main__":
    main()
